from flask import Flask, request, jsonify
import os
import io
import uuid
import shutil
import threading
from datetime import datetime

import pandas as pd
import numpy as np
from PIL import Image

import tensorflow as tf
from tensorflow.keras import layers, models

BASE_DIR = os.path.abspath(os.path.dirname(__file__))
UPLOAD_DIR = os.path.join(BASE_DIR, "uploads")
DATASET_DIR = os.path.join(BASE_DIR, "dataset")
MODEL_DIR = os.path.join(BASE_DIR, "model_store")
MODEL_PATH = os.path.join(MODEL_DIR, "community_image_model.keras")
LABELS_PATH = os.path.join(MODEL_DIR, "labels.txt")
TRAINING_LOCK = threading.Lock()

IMAGE_SIZE = (128, 128)
BATCH_SIZE = 32
EPOCHS = 5

app = Flask(__name__)
os.makedirs(UPLOAD_DIR, exist_ok=True)
os.makedirs(DATASET_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)


def load_labels():
    if os.path.exists(LABELS_PATH):
        with open(LABELS_PATH, "r", encoding="utf-8") as f:
            return [line.strip() for line in f if line.strip()]
    return []


def save_labels(labels):
    with open(LABELS_PATH, "w", encoding="utf-8") as f:
        for label in labels:
            f.write(f"{label}\n")


def allowed_image_ext(filename):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in {"png", "jpg", "jpeg", "bmp", "gif", "webp"}


def sanitize_label(label):
    label = str(label).strip()
    if not label:
        raise ValueError("Invalid empty label")
    return "".join(c if c.isalnum() or c in ("-", "_") else "_" for c in label)


def ensure_label_dir(label):
    label = sanitize_label(label)
    label_dir = os.path.join(DATASET_DIR, label)
    os.makedirs(label_dir, exist_ok=True)
    return label, label_dir


def save_image_file(file_storage, label):
    if not file_storage or not file_storage.filename:
        raise ValueError("Missing file")
    if not allowed_image_ext(file_storage.filename):
        raise ValueError("Unsupported image file type")
    label, label_dir = ensure_label_dir(label)
    ext = file_storage.filename.rsplit(".", 1)[1].lower()
    filename = f"{datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex}.{ext}"
    path = os.path.join(label_dir, filename)
    image = Image.open(file_storage.stream).convert("RGB")
    image.save(path)
    return path, label


def load_csv_and_import(csv_file):
    df = pd.read_csv(csv_file)
    required = {"label", "image_path"}
    if not required.issubset(df.columns):
        raise ValueError("CSV must contain columns: label,image_path")

    imported = 0
    for _, row in df.iterrows():
        label = sanitize_label(row["label"])
        image_path = str(row["image_path"]).strip()
        if not image_path or not os.path.isfile(image_path):
            continue
        _, label_dir = ensure_label_dir(label)
        ext = image_path.rsplit(".", 1)[-1].lower()
        if ext not in {"png", "jpg", "jpeg", "bmp", "gif", "webp"}:
            continue
        filename = f"{datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex}.{ext}"
        shutil.copy2(image_path, os.path.join(label_dir, filename))
        imported += 1
    return imported


def load_dataset():
    dataset = tf.keras.utils.image_dataset_from_directory(
        DATASET_DIR,
        labels="inferred",
        label_mode="int",
        image_size=IMAGE_SIZE,
        batch_size=BATCH_SIZE,
        shuffle=True,
        validation_split=0.2,
        subset="both",
        seed=42,
    )
    train_ds, val_ds = dataset
    class_names = train_ds.class_names

    autotune = tf.data.AUTOTUNE
    train_ds = train_ds.cache().shuffle(1000).prefetch(buffer_size=autotune)
    val_ds = val_ds.cache().prefetch(buffer_size=autotune)
    return train_ds, val_ds, class_names


def build_model(num_classes):
    data_augmentation = tf.keras.Sequential([
        layers.RandomFlip("horizontal"),
        layers.RandomRotation(0.1),
        layers.RandomZoom(0.1),
    ])

    model = models.Sequential([
        layers.Input(shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3)),
        data_augmentation,
        layers.Rescaling(1.0 / 255),
        layers.Conv2D(32, 3, activation="relu"),
        layers.MaxPooling2D(),
        layers.Conv2D(64, 3, activation="relu"),
        layers.MaxPooling2D(),
        layers.Conv2D(128, 3, activation="relu"),
        layers.MaxPooling2D(),
        layers.Flatten(),
        layers.Dense(128, activation="relu"),
        layers.Dropout(0.3),
        layers.Dense(num_classes, activation="softmax"),
    ])

    model.compile(
        optimizer="adam",
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


def train_model():
    with TRAINING_LOCK:
        train_ds, val_ds, class_names = load_dataset()
        if len(class_names) < 2:
            raise ValueError("Need at least 2 classes to train an image classification model")

        model = build_model(len(class_names))
        history = model.fit(
            train_ds,
            validation_data=val_ds,
            epochs=EPOCHS,
            verbose=1,
        )
        model.save(MODEL_PATH)
        save_labels(class_names)
        final_metrics = {
            "loss": float(history.history["loss"][-1]),
            "accuracy": float(history.history["accuracy"][-1]),
            "val_loss": float(history.history["val_loss"][-1]),
            "val_accuracy": float(history.history["val_accuracy"][-1]),
            "classes": class_names,
        }
        return final_metrics


def load_trained_model():
    if not os.path.exists(MODEL_PATH):
        return None, []
    model = tf.keras.models.load_model(MODEL_PATH)
    labels = load_labels()
    return model, labels


def predict_image(file_storage):
    model, labels = load_trained_model()
    if model is None or not labels:
        raise ValueError("No trained model available")

    image = Image.open(file_storage.stream).convert("RGB").resize(IMAGE_SIZE)
    arr = np.array(image, dtype=np.float32)
    arr = np.expand_dims(arr, axis=0)

    preds = model.predict(arr, verbose=0)[0]
    idx = int(np.argmax(preds))
    return {
        "predicted_label": labels[idx],
        "confidence": float(preds[idx]),
        "scores": {labels[i]: float(preds[i]) for i in range(len(labels))}
    }


def count_dataset():
    counts = {}
    total = 0
    if not os.path.isdir(DATASET_DIR):
        return {"total": 0, "classes": {}}
    for name in sorted(os.listdir(DATASET_DIR)):
        path = os.path.join(DATASET_DIR, name)
        if os.path.isdir(path):
            n = len([
                f for f in os.listdir(path)
                if os.path.isfile(os.path.join(path, f))
            ])
            counts[name] = n
            total += n
    return {"total": total, "classes": counts}


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


@app.route("/upload-example", methods=["POST"])
def upload_example():
    try:
        label = request.form.get("label", "").strip()
        if not label:
            return jsonify({"error": "label is required"}), 400
        if "file" not in request.files:
            return jsonify({"error": "file is required"}), 400

        path, clean_label = save_image_file(request.files["file"], label)
        return jsonify({
            "message": "Training example uploaded",
            "label": clean_label,
            "path": path
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/upload-csv", methods=["POST"])
def upload_csv():
    try:
        if "file" not in request.files:
            return jsonify({"error": "CSV file is required"}), 400
        csv_file = request.files["file"]
        imported = load_csv_and_import(csv_file)
        return jsonify({
            "message": "CSV processed",
            "imported_examples": imported
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/train", methods=["POST"])
def train():
    try:
        stats = count_dataset()
        if stats["total"] < 2 or len(stats["classes"]) < 2:
            return jsonify({"error": "Need at least 2 images across 2 classes to train"}), 400
        metrics = train_model()
        return jsonify({
            "message": "Model trained successfully",
            "metrics": metrics,
            "dataset": stats
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/predict", methods=["POST"])
def predict():
    try:
        if "file" not in request.files:
            return jsonify({"error": "image file is required"}), 400
        result = predict_image(request.files["file"])
        return jsonify(result)
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/dataset-stats", methods=["GET"])
def dataset_stats():
    return jsonify(count_dataset())


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=False)